     1→/*
     2→ * expf() test harness — prints (input_hex, output_hex) pairs.
     3→ *
     4→ * Build two versions:
     5→ *   1. Linked with optimized Andes assembly expf  (test_expf_opt.elf)
     6→ *   2. Linked with toolchain's default expf        (test_expf_ref.elf)
     7→ * Run both, diff the output to find discrepancies.
     8→ */
     9→
    10→#include <math.h>
    11→#include <stdint.h>
    12→#include <stdio.h>
    13→#include <float.h>
    14→
    15→#ifdef EN_PERF
    16→#define PF_COUNTER
    17→#include "nds_pfcounter.h"
    18→#endif
    19→
    20→static inline uint32_t f2u(float f)
    21→{
    22→    union { float f; uint32_t u; } x;
    23→    x.f = f;
    24→    return x.u;
    25→}
    26→
    27→static inline float u2f(uint32_t u)
    28→{
    29→    union { float f; uint32_t u; } x;
    30→    x.u = u;
    31→    return x.f;
    32→}
    33→
    34→#ifndef EN_PERF
    35→static void emit(float x)
    36→{
    37→    float r = expf(x);
    38→    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
    39→}
    40→
    41→static void emit_u(uint32_t bits)
    42→{
    43→    emit(u2f(bits));
    44→}
    45→
    46→/* ------------------------------------------------------------------ */
    47→/* Test points                                                         */
    48→/* ------------------------------------------------------------------ */
    49→
    50→/* 1. Special values */
    51→static void test_special(void)
    52→{
    53→    /* Zeros */
    54→    emit(0.0f);
    55→    emit(-0.0f);
    56→
    57→    /* NaN */
    58→    emit_u(0x7fc00000u); /* qNaN */
    59→    emit_u(0x7f800001u); /* sNaN */
    60→    emit_u(0xffc00000u); /* -NaN */
    61→
    62→    /* Infinity */
    63→    emit_u(0x7f800000u); /* +Inf */
    64→    emit_u(0xff800000u); /* -Inf */
    65→}
    66→
    67→/* 2. Tiny values: exp(x) ~ 1 for very small |x| */
    68→static void test_tiny(void)
    69→{
    70→    emit_u(0x00000001u); /* min denorm */
    71→    emit_u(0x80000001u);
    72→    emit_u(0x00400000u); /* mid denorm */
    73→    emit_u(0x80400000u);
    74→    emit_u(0x007fffffu); /* max denorm */
    75→    emit_u(0x807fffffu);
    76→    emit(FLT_MIN);
    77→    emit(-FLT_MIN);
    78→    emit(1.0e-20f);
    79→    emit(-1.0e-20f);
    80→    emit(1.0e-10f);
    81→    emit(-1.0e-10f);
    82→}
    83→
    84→/* 3. Known mathematical values */
    85→static void test_known(void)
    86→{
    87→    float e      = 2.71828182845904523536f;
    88→    float ln2    = 0.69314718055994530942f;
    89→    float ln10   = 2.30258509299404568402f;
    90→    float e_sq   = 7.38905609893065022723f;  /* exp(2) */
    91→    float e_half = 1.64872127070012814087f;  /* exp(0.5) */
    92→    float inv_e  = 0.36787944117144232160f;  /* exp(-1) */
    93→
    94→    emit(ln2);    /* exp(ln(2)) -> 2 */
    95→    emit(ln10);   /* exp(ln(10)) -> 10 */
    96→    emit(1.0f);   /* exp(1) -> e */
    97→    emit(-1.0f);  /* exp(-1) -> 1/e */
    98→    emit(0.5f);   /* exp(0.5) */
    99→    emit(-0.5f);
   100→    emit(2.0f);   /* exp(2) */
   101→    emit(-2.0f);
   102→    emit(0.1f);
   103→    emit(-0.1f);
   104→    emit(e);      /* exp(e) = e^e */
   105→    emit(e_sq);   /* exp(e^2) */
   106→    emit(e_half); /* exp(sqrt(e)) */
   107→    emit(inv_e);  /* exp(1/e) */
   108→}
   109→
   110→/* 4. Large arguments (near overflow/underflow) */
   111→static void test_large(void)
   112→{
   113→    float vals[] = {
   114→        u2f(0x42d4e000u), /* ~105.375, near overflow */
   115→        u2f(0xc2d40000u), /* near underflow */
   116→        10.0f, 50.0f, 80.0f, 100.0f,
   117→        -10.0f, -50.0f, -80.0f, -100.0f,
   118→        1.0e10f, 1.0e20f,
   119→        -1.0e10f, -1.0e20f,
   120→        FLT_MAX, -FLT_MAX,
   121→    };
   122→    int n = sizeof(vals) / sizeof(vals[0]);
   123→    for (int i = 0; i < n; i++)
   124→        emit(vals[i]);
   125→}
   126→
   127→/* 5. Boundary transitions */
   128→static void test_quadrant(void)
   129→{
   130→    float boundaries[] = { -1.0f, 0.0f, 1.0f, 10.0f, 88.0f, 89.0f };
   131→    float offsets[] = { -1e-5f, 0.0f, 1e-5f };
   132→    int nbnd = sizeof(boundaries) / sizeof(boundaries[0]);
   133→    int noff = sizeof(offsets) / sizeof(offsets[0]);
   134→
   135→    for (int k = 0; k < nbnd; k++) {
   136→        for (int j = 0; j < noff; j++)
   137→            emit(boundaries[k] + offsets[j]);
   138→    }
   139→}
   140→
   141→/* 6. Worst-case argument values */
   142→static void test_hard(void)
   143→{
   144→    float cases[] = {
   145→        u2f(0x3f317217u), /* ln(2) as float */
   146→        u2f(0x42b17218u), /* overflow threshold */
   147→        u2f(0xc2aeac50u), /* underflow threshold */
   148→        0.30102999566f,   /* log10(2) */
   149→        0.43429448190f,   /* 1/ln(10) */
   150→        4.0f, 16.0f, 64.0f, 256.0f,
   151→    };
   152→    int n = sizeof(cases) / sizeof(cases[0]);
   153→    for (int i = 0; i < n; i++) {
   154→        emit(cases[i]);
   155→        emit(-cases[i]);
   156→    }
   157→}
   158→
   159→/* 7. Sweep [-10, 10] in 200 steps */
   160→static void test_sweep(void)
   161→{
   162→    float lo = -10.0f;
   163→    float hi = 10.0f;
   164→    int nsteps = 200;
   165→    float step = (hi - lo) / (float)nsteps;
   166→
   167→    for (int i = 0; i <= nsteps; i++)
   168→        emit(lo + (float)i * step);
   169→}
   170→
   171→/* 8. Sample [0, 1] every 4194304 ULP (~1000 cases) */
   172→static void test_exhaustive_small(void)
   173→{
   174→    uint32_t end = 0x3f800000u; /* 1.0 */
   175→    for (uint32_t b = 0; b <= end; b += 4194304)
   176→        emit_u(b);
   177→}
   178→
   179→/* 9. Random sweep: 300 evenly spaced inputs */
   180→static void test_random_300(void)
   181→{
   182→    float lo = -10.0f;
   183→    float hi =  10.0f;
   184→    int n = 300;
   185→    for (int i = 0; i < n; i++) {
   186→        float x = lo + (hi - lo) * (float)i / (float)(n - 1);
   187→        emit(x);
   188→    }
   189→}
   190→#endif
   191→
   192→/* ------------------------------------------------------------------ */
   193→
   194→#ifdef EN_PERF
   195→static void perf(float x)
   196→{
   197→    volatile float acc = 0.0f;
   198→    startPFM;
   199→    for (int i = 0; i < 100; i++)
   200→        acc += expf(x+i);
   201→    stopPFM;
   202→    readResult();
   203→    printf("perf %08lx: %08lx\n",
   204→           (unsigned long)f2u(x),
   205→           (unsigned long)f2u((float)acc));
   206→}
   207→#endif /* EN_PERF */
   208→
   209→/* ------------------------------------------------------------------ */
   210→
   211→int main(void)
   212→{
   213→#ifdef EN_PERF
   214→    perf(1.0f);
   215→#else
   216→    test_special();
   217→    test_tiny();
   218→    test_known();
   219→    test_large();
   220→    test_quadrant();
   221→    test_hard();
   222→    test_sweep();
   223→    test_exhaustive_small();
   224→    test_random_300();
   225→#endif
   226→    return 0;
   227→}
