      "expected": "expf(ln10) -> 10.0f"
    },
    "overflow_threshold": {
      "count": 6,
      "threshold_float": "0x42b17218 (~88.7228)",
      "cases": ["88.0", "88.5", "threshold", "threshold-1ULP (last finite)", "threshold+1ULP (first Inf)", "89.0"]
    },
    "underflow_threshold": {
      "count": 6,
      "threshold_float": "0xc2cff1b5 (~-103.972)",
      "cases": ["-87.0", "-100.0", "-103.0", "near-floor", "just-above-floor (nonzero)", "just-below-floor (zero)"]
    },
    "known_integer_half_integer": {
      "count": 14,
      "cases": ["+/-1", "+/-2", "+/-3", "+/-4", "+/-0.5", "+/-1.5", "+/-0.25"]
    },
    "polynomial_boundary": {
      "count": 4,
      "notes": "probes +/-0.5*ln2, the reduction kernel boundary",
      "cases": ["0.5*ln2", "-0.5*ln2", "0.5*ln2 bit-exact", "-0.5*ln2 bit-exact"]
    },
    "medium_scale": {
      "count": 12,
      "cases": ["+/-10", "+/-20", "+/-40", "+/-50", "+/-70", "+/-80"]
    },
    "powers_of_2_as_args": {
      "count": 6,
      "cases": ["8", "16", "32", "64", "-8", "-16"]
    },
    "large_saturating": {
      "count": 4,
      "cases": ["1e10 -> +Inf", "-1e10 -> 0", "FLT_MAX -> +Inf", "-FLT_MAX -> 0"]
    },
    "hard_polynomial": {
      "count": 14,
      "cases": ["+/-0.1", "+/-0.3", "+/-0.7", "+/-1.2", "+/-2.5", "+/-5.0", "log10(2)", "1/ln(10)"]
    }
  },
  "notes": [
    "All emit() and emit_u() calls are inside #ifndef EN_PERF guard matching harness convention.",
    "No redefinition of emit/emit_u/f2u/u2f — those are provided by the existing test file.",
    "Overflow threshold 0x42b17218 = 88.7228...; underflow threshold 0xc2cff1b5 = -103.972...",
